INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-08120', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在十九世紀末與二十世紀初，當慈善組織會社（COS）興起之時，實務工作者的專業使命是協助貧窮、失業、 無家可歸者運用自己的內在能力去過有意義、有德行的生活，不依賴政府或民間的財源幫助。這是屬於何 種實務工作者的價值觀？', '["父權主義取向", "社會正義取向", "臨床取向", "專業自我保衛取向"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08121', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作實務中，社會工作者必須以清楚和易懂的言詞告知案主：服務的目標、風險、相關的費用、合 理的選擇方案、案主可以拒絕或撤回同意的權利等，這是基於何種對案主的倫理責任？', '["對案主的承諾", "自我決定", "利益衝突", "知後同意"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08122', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「當社會工作者要在新的領域提供服務、使用新的介入技術或取向，僅應在相當的研習、訓練、諮詢或接 受該介入技術或取向的專家督導下才可運用」，這是遵守何種社會工作倫理？', '["文化能力與社會多元", "能力", "隱私與保密", "科技合作"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08123', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「社會工作者如與現有或先前的案主產生雙重或多重關係，而可能產生對案主傷害的風險」，這是陷於何 種倫理兩難？', '["專業與個人價值", "保密與隱私權", "自我決定與父權主義", "專業界線與利益衝突"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08124', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'NASW 所頒訂的倫理守則中，其中有一項社會工作價值與倫理是「社會工作者的行為應是值得信賴的」， 它要求社會工作者在從事各種行動和提供服務時，能夠誠實和負責，這是屬於何者社會工作價值？', '["稱職（competence）", "正直（integrity）", "人群關係的重要性（importance of human relationships）", "個人的尊嚴與價值（dignity and worth of the person）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08125', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Reamer提出一套處理社工實務中倫理困境的原則，有關其優先順序之敘述，下列何者錯誤？', '["人們在自由意志下同意遵守的法律或機構規定凌駕於個人的信仰、價值與原則", "保護生命免於受傷害優先於其他一些傷害，例如欺騙或揭發隱私", "其他人的自我決定權優先於個人基本福祉的權利", "個人自決權優先於自身基本幸福權的考量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08126', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社區照顧實務工作中，社會工作者需要協助社區建構照顧網絡，如果社會工作者連結鄰里和地方菁英者 形成一個關係網絡，其目標是要協助孤立的個人，促進地方的互助，確認地方議題和提升非正式的社會組 織。這是屬於何種社會網絡？', '["個人網絡", "志工連結網絡", "鄰里協助網絡", "社區充權網絡"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08127', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關老人長期照顧服務之敘述，下列敘述何者是錯誤的？', '["長期照顧服務內容包含預防、診斷、治療、復健、支持、維持及社會等服務", "長期照顧服務具有以「生活照顧為主，醫療照顧為輔」之特質", "長期照顧是需要醫療與福利服務結合之領域", "通常用來測量老人的功能指標之兩種工具，ADL是評估機能性日常生活活動，IADL是評估日常生活自我 照顧活動"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08128', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '1994年美國柯林頓總統將1965年的國中小學教育法（EAEA），授權革新為美國學校法案（IASA），此法 支持學校致力於讓所有學童都獲得較高的學業成就，其作法包含針對處在危機中的學童，透過有效方案的 引導提升教學，以及將資源集中投注在貧困學生比例最高的學區上、催化最貧困社區的澈底改變，此種干 預策略是屬於何種學校社會工作模式？', '["學校變遷模式", "傳統臨床模式", "社區學校模式", "社會互動模式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08129', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是以短期的危機介入服務避免在危機中的兒童被移離家庭？', '["家庭為中心的服務（family centered services）", "家庭為基礎的服務（home-based services）", "密集家庭維護服務（intensive family preservation services）", "家族治療（family therapy）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
